<script setup lang="ts">
import {computed,onMounted,ref} from 'vue';import {BookOpen,Brain,Clock3,Link2,Plus,Save} from 'lucide-vue-next';import {wikiApi} from '../api/wiki';const pages=ref<any[]>([]),memories=ref<any[]>([]),selected=ref<any>(null),newMemory=ref('');async function load(){pages.value=await wikiApi.pages();memories.value=await wikiApi.memories();selected.value=pages.value[0]}async function add(){if(!newMemory.value.trim())return;await wikiApi.createMemory({scope:'stock',memory_type:'risk_note',ts_code:'600519.SH',title:'研究员补充',content:newMemory.value,confidence:.8});newMemory.value='';memories.value=await wikiApi.memories()}onMounted(load);const graphOption=computed(()=>({tooltip:{},series:[{type:'graph',layout:'force',roam:true,label:{show:true},force:{repulsion:180},data:[{name:'贵州茅台',symbolSize:58,itemStyle:{color:'#2563eb'}},{name:'食品饮料',symbolSize:40,itemStyle:{color:'#10b981'}},{name:'高端白酒',symbolSize:40,itemStyle:{color:'#8b5cf6'}},{name:'品牌壁垒',symbolSize:34,itemStyle:{color:'#f59e0b'}},{name:'渠道库存',symbolSize:34,itemStyle:{color:'#ef4444'}}],links:[{source:'贵州茅台',target:'食品饮料'},{source:'贵州茅台',target:'高端白酒'},{source:'贵州茅台',target:'品牌壁垒'},{source:'高端白酒',target:'渠道库存'}]}]}))
import BaseChart from '../components/charts/BaseChart.vue'
</script>
<template><div class="split-3"><aside class="panel"><div class="panel-title"><BookOpen :size="17"/><h2>知识库</h2><Plus class="spacer" :size="16"/></div><div class="list-panel"><div class="list-item active"><span>公司研究</span><span>{{pages.length}}</span></div><div class="list-item"><span>行业研究</span><span>12</span></div><div class="list-item"><span>概念与方法</span><span>26</span></div><div class="list-item"><span>分析框架</span><span>10</span></div><div class="list-item"><span>个人笔记</span><span>18</span></div></div><div class="panel-title"><h2>页面列表</h2></div><div class="list-panel"><div v-for="p in pages" :key="p.id" class="list-item" :class="{active:selected?.id===p.id}" @click="selected=p"><span>{{p.title}}</span></div></div></aside><section class="grid"><article class="panel"><div class="panel-title"><h2>{{selected?.title||'Wiki 页面'}}</h2><span class="spacer status-badge success">{{selected?.freshness||'unknown'}}</span><button class="btn"><Save :size="14"/>保存</button></div><pre class="markdown">{{selected?.content_md}}</pre></article><article class="panel chart-panel"><div class="panel-title"><Link2 :size="16"/><h2>关联图谱</h2></div><div class="panel-body"><BaseChart :option="graphOption" :height="260"/></div></article></section><aside class="panel"><div class="panel-title"><Brain :size="17"/><h2>长期记忆</h2><span class="spacer status-badge info">{{memories.length}}</span></div><div class="panel-body"><textarea v-model="newMemory" rows="3" placeholder="记录新的投资假设、观察指标或风险变化"></textarea><button class="btn primary" style="margin-top:8px" @click="add"><Plus :size="15"/>写入长期记忆</button></div><div v-for="m in memories" :key="m.id" style="padding:14px;border-top:1px solid var(--color-border)"><div style="display:flex;justify-content:space-between"><b>{{m.title}}</b><span class="status-badge success">{{Math.round(m.confidence*100)}}%</span></div><p>{{m.content}}</p><small class="muted"><Clock3 :size="12"/> {{m.source}} · {{m.updated_at?.slice(0,10)}}</small></div><p class="disclaimer">记忆有 scope、confidence 和来源，可编辑、查询与失效。</p></aside></div></template>

